final:
module RefModule(
    input wire clk,
    input wire rst_n,
    input wire req,
    output reg rsp
);

    reg obf_req_d;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rsp <= 1'b0;
            obf_req_d <= 1'b0;
        end else begin
            obf_req_d <= req;
            rsp <= obf_req_d;
        end
    end
endmodule
